#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 5 (Layer 3): sondas de protocolo.
# Verifica ANTES de construir el secuenciador que:
#   1. el tiling de canales reproduce el oraculo bit a bit (Python)
#   2. la secuencia completa da clases y firma identicas al oraculo (32 imgs)
#   3. el array entrega las sumas parciales CRUDAS de un tile real de conv2
#   4. las filas ociosas no arrastran residuos entre capas
# Requiere: ghdl 4.1.0 --std=08, python3. Requiere Pasos 1, 2 y 3.
# Linea esperada al final:
# NPU PASO5 OK L3 SONDAS 4/4 PASS
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/model/npu_weights.hex" ] || [ ! -f "$DIR/rtl/npu_array.vhd" ]; then
  echo "FALLO: faltan Pasos 1-3 en $DIR"; exit 1
fi
mkdir -p "$DIR/rtl" "$DIR/tb" "$DIR/vec"
base64 -d << "EOF" > "$DIR/tb/tb_l3_sonda.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_l3_ocio.vhd"

EOF
base64 -d << "EOF" > "$DIR/sonda_l3_tiling.py"

EOF
base64 -d << "EOF" > "$DIR/sonda_l3_secuencia.py"

EOF
base64 -d << "EOF" > "$DIR/gen_l3_sonda.py"

EOF
base64 -d << "EOF" > "$DIR/run_l3_sondas.sh"

EOF
chmod +x "$DIR/run_l3_sondas.sh"
cd "$DIR"
bash run_l3_sondas.sh
)
